<?php $adminTitle='LMS Progress'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; $rows=$pdo->query('SELECT e.learner_id,e.course_id,l.full_name,c.title FROM lms_enrollments e JOIN learners l ON l.id=e.learner_id JOIN lms_courses c ON c.id=e.course_id ORDER BY e.enrolled_at DESC')->fetchAll(); ?><h1>Learner Progress</h1><div class="glass-card"><table class="table table-dark"><tr><th>Learner</th><th>Course</th><th>Completed</th><th>Pending</th><th>Progress</th><th>Quiz</th></tr><?php foreach($rows as $r): $p=course_progress($pdo,(int)$r['learner_id'],(int)$r['course_id']); $a=latest_quiz_attempt($pdo,(int)$r['learner_id'],(int)$r['course_id']); ?><tr><td><?= e($r['full_name']); ?></td><td><?= e($r['title']); ?></td><td><?= $p['done']; ?></td><td><?= $p['pending']; ?></td><td><?= $p['percent']; ?>%</td><td><?= $a ? (int)$a['percentage'].'%' : 'No attempt'; ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>